    ios::sync_with_stdio(false); cin.tie(nullptr);
    int n, a, b; cin >> n >> a >> b;
    vector<ll> p(n + 1);
    for (int i = 1; i <= n; i++) { cin >> p[i]; p[i] += p[i - 1]; }
    deque<int> q; ll ans = LLONG_MIN;
