        while (!q.empty() && q.front() < r - b) q.pop_front();
        int l = r - a;
        while (!q.empty() && p[q.back()] >= p[l]) q.pop_back();
        q.push_back(l);
        ans = max(ans, p[r] - p[q.front()]);
    }
    cout << ans << '\n';
}

