const int MOD = 1e9 + 7;

vector<int> bit;

void add(int i, int x) {
    for (; i < (int)bit.size(); i += i & -i) {
        bit[i] += x;
        if (bit[i] >= MOD) bit[i] -= MOD;
    }
}

int get(int i) {
    int ans = 0;

    for (; i > 0; i -= i & -i) {
        ans += bit[i];
        if (ans >= MOD) ans -= MOD;
    }

    return ans;
}

