const int MOD = 1e9 + 7;

int n;
vector<vector<int>> trans;

void gen(int row, int mask, int next) {
    if (row == n) {
        trans[mask].push_back(next);
        return;
    }

    if (mask & (1 << row)) {
        gen(row + 1, mask, next);
        return;
    }

    gen(row + 1, mask, next | (1 << row));

    if (row + 1 < n && !(mask & (1 << (row + 1)))) {
        gen(row + 2, mask, next);
    }
}

