    dp[0] = 1;

    for (int col = 0; col < m; col++) {
        fill(ndp.begin(), ndp.end(), 0);

        for (int mask = 0; mask < states; mask++) {
            for (int next : trans[mask]) {
                ndp[next] += dp[mask];
                if (ndp[next] >= MOD) ndp[next] -= MOD;
            }
        }

        dp.swap(ndp);
    }

