                pq.push({nd, to});
            } else if (nd == dist[to]) {
                ways[to] = (ways[to] + ways[v]) % MOD;
                mn[to] = min(mn[to], mn[v] + 1);
                mx[to] = max(mx[to], mx[v] + 1);
