    for (int i = (int)order.size() - 1; i >= 0; i--) { // reverse topo
        int v = order[i];
        for (int to : adj[v]) {
            if (dp[to] != INT_MIN && dp[to] + 1 > dp[v]) {
                dp[v] = dp[to] + 1;
                nxt[v] = to;
            }
        }
    }
    if (dp[1] < 0) {
        cout << "IMPOSSIBLE\n";
        return 0;
    }
    cout << dp[1] << '\n';
    vector<int> path;
    for (int v = 1; v != -1; v = nxt[v]) path.push_back(v);
    for (int i = 0; i < (int)path.size(); i++)
        cout << path[i] << (i + 1 == (int)path.size() ? '\n' : ' ');
