using ll = long long;
const int MOD = 1e9 + 7;
int n, m;
int cnt[20][20]; // cnt[v][u]: number of edges v->u
int dp[1 << 20][20];

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    cin >> n >> m;
    for (int i = 0; i < m; i++) {
        int a, b;
        cin >> a >> b;
        cnt[a - 1][b - 1]++;
    }
    dp[1][0] = 1; // start at city 0 (=1), set {0}
    for (int S = 1; S < (1 << n); S++) {
        if (!(S & 1)) continue; // must contain start
        for (int v = 0; v < n; v++) {
            if (!dp[S][v] || !(S >> v & 1)) continue;
            int cur = dp[S][v];
            for (int u = 0; u < n; u++) {
                if ((S >> u & 1) || !cnt[v][u]) continue; // u visited or no edge
                int& t = dp[S | (1 << u)][u];
                t = (t + (ll)cur * cnt[v][u]) % MOD; // multiply by edge multiplicity
            }
        }
    }
    cout << dp[(1 << n) - 1][n - 1] << '\n';
}

#include <bits/stdc++.h>
using namespace std;

using ll = long long;
using ii = pair<ll, ll>;
int dr[8] = {1, 1, -1, -1, 2, 2, -2, -2};
int dc[8] = {2, -2, 2, -2, 1, -1, 1, -1};
int board[8][8];
bool inb(int r, int c) {
    return r >= 0 && r < 8 && c >= 0 && c < 8;
}
int deg(int r, int c) {
    int d = 0;
    for (int k = 0; k < 8; k++) {
        int nr = r + dr[k], nc = c + dc[k];
        if (inb(nr, nc) && board[nr][nc] == 0) d++;
    }
    return d;
}
bool solve(int r, int c, int step) {
    board[r][c] = step;
    if (step == 64) return true;
    vector<pair<int, ii>> cand;
    for (int k = 0; k < 8; k++) {
        int nr = r + dr[k], nc = c + dc[k];
        if (inb(nr, nc) && board[nr][nc] == 0) cand.push_back({deg(nr, nc), {nr, nc}});
    }
    sort(cand.begin(), cand.end());
    for (auto& e : cand) {
        int nr = e.second.first, nc = e.second.second;
        if (solve(nr, nc, step + 1)) return true;
    }
    board[r][c] = 0;
    return false;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int x, y;
    cin >> x >> y;
    int c = x - 1, r = y - 1;
    solve(r, c, 1);
    for (int i = 0; i < 8; i++)
        for (int j = 0; j < 8; j++) cout << board[i][j] << (j == 7 ? '\n' : ' ');
}

