    sz = 1;
    while (sz < n) sz <<= 1;
    t.assign(2*sz, LLONG_MAX);

    for (int i = 0; i < n; i++) cin >> t[sz + i];
    for (int i = sz - 1; i >= 1; i--) t[i] = min(t[i<<1], t[i<<1|1]);

    while (q--){
        int op; cin >> op;
        if (op == 1){
            int k; ll u; cin >> k >> u;
            upd(k - 1, u);
        } else {
            int a, b; cin >> a >> b;
            cout << qry(a - 1, b) << '\n';
        }
    }
    return 0;
}

