        if (type == 1) {
            int s; ll x; cin >> s >> x;
            radd(tin[s], tout_[s], x - val[s]);
            val[s] = x;
        } else {
            int s; cin >> s;
            cout << qry(tin[s]) << '\n';
        }
    }
    return 0;
}

