    int mx = 0;
    for (int i = 1; i <= n; i++) {
        int x;
        cin >> x;
        p[i] = p[i - 1] ^ x;
        mx = max(mx, p[i]);
    }

    int m = 1;
    while (m <= mx) m <<= 1;

    vector<ll> f(m);
    bool dup = false;
    for (int x : p) {
        if (f[x]) dup = true;
        f[x]++;
    }

    fwht(f);
    for (ll& x : f) x *= x;
    fwht(f);
    for (ll& x : f) x /= m;

    vector<int> ans;
    for (int x = 0; x < m; x++) {
        if ((x == 0 && dup) || (x > 0 && f[x] > 0)) ans.push_back(x);
    }

