#include <bits/stdc++.h>
using namespace std;

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    cin >> n;

    vector<int> a(n + 1), b(n + 1), pos(n + 1), s(n + 1), ans(n + 1), vis(n + 1);

    for (int i = 1; i <= n; i++) {
        cin >> a[i];
        pos[a[i]] = i;
    }

    for (int i = 1; i <= n; i++) {
        cin >> b[i];
        s[i] = pos[b[i]];
    }

    if (n == 2) {
        cout << "IMPOSSIBLE\n";
        return 0;
    }

    vector<array<int, 2>> two;
    vector<vector<int>> big;

    for (int i = 1; i <= n; i++) {
        if (vis[i]) continue;

        vector<int> cyc;
