#include <bits/stdc++.h>
using namespace std;

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, m;
    cin >> n >> m;
    vector<vector<int>> g(n + 1);
    vector<pair<int,int>> edges;
    for(int i = 0; i < m; ++i){
        int a, b; cin >> a >> b;
        g[a].push_back(b);
        edges.push_back({a,b});
    }

    vector<int> arr(n + 1, 0), rev(n + 1), parVertex(n + 1, 0), it(n + 1, 0);
    int timer = 1; arr[1] = 1; rev[1] = 1;
    vector<int> st{1};
    while(!st.empty()){
        int u = st.back();
        if(it[u] == (int)g[u].size()){ st.pop_back(); continue; }
        int v = g[u][it[u]++];
        if(!arr[v]){
            arr[v] = ++timer; rev[timer] = v; parVertex[v] = u;
            st.push_back(v);
        }
    }

    int N = timer;
    vector<vector<int>> pred(N + 1), bucket(N + 1);
    for(auto [u,v] : edges) if(arr[u] && arr[v]) pred[arr[v]].push_back(arr[u]);
    vector<int> parent(N + 1), sdom(N + 1), dom(N + 1), dsu(N + 1), label(N + 1);
    for(int i = 1; i <= N; ++i){
        sdom[i] = dsu[i] = label[i] = i;
        if(i > 1) parent[i] = arr[parVertex[rev[i]]];
    }

    function<int(int,int)> find = [&](int v, int depth){
        if(v == dsu[v]) return depth ? -1 : v;
        int p = find(dsu[v], depth + 1);
        if(p < 0) return v;
        if(sdom[label[dsu[v]]] < sdom[label[v]]) label[v] = label[dsu[v]];
        dsu[v] = p;
        return depth ? p : label[v];
    };

    for(int i = N; i >= 1; --i){
        for(int p : pred[i]) sdom[i] = min(sdom[i], sdom[find(p,0)]);
        if(i > 1) bucket[sdom[i]].push_back(i);
        for(int v : bucket[i]){
            int y = find(v,0);
            dom[v] = (sdom[y] == sdom[v] ? sdom[v] : y);
        }
        if(i > 1) dsu[i] = parent[i];
    }
    for(int i = 2; i <= N; ++i) if(dom[i] != sdom[i]) dom[i] = dom[dom[i]];
    dom[1] = 1;

    vector<int> ans;
    if(arr[n]){
        for(int v = arr[n]; ; v = dom[v]){
            ans.push_back(rev[v]);
            if(v == 1) break;
        }
    }
    sort(ans.begin(), ans.end());
    cout << ans.size() << '\n';
    for(int i = 0; i < (int)ans.size(); ++i) cout << ans[i] << " \n"[i + 1 == (int)ans.size()];
}

