const ll MOD = 1e9 + 7;

static int bitarr[3005], remHead[3005], remNext[3005], RA[3005], LB[3005], vG[3005];

int main(){
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, k;
