    for (int m = 1; m <= n; m++) a[m] = sc[m] * inv[m] % MOD;

    vi cur = a;                                // cur = S^k, start k=1
    int lo = 1;
    cout << fc[n] * cur[n] % MOD << "\n";       // T(n,1)
    for (int k = 2; k <= n; k++) {
        vi nx(n + 1, 0);
        lo++;                                  // S^k supported from degree k
        for (int i = lo - 1; i <= n; i++) {
            if (!cur[i]) continue;
            for (int j = 1; j + i <= n; j++)
                nx[i + j] = (nx[i + j] + cur[i] * a[j]) % MOD;
        }
        cur = move(nx);
        cout << fc[n] * cur[n] % MOD << "\n";
    }
}

