using cd = complex<double>;
const double PI = acos(-1.0);

void fft(vector<cd>& a, bool inv) {
    int n = a.size();

    for(int i = 1, j = 0; i < n; i++) {
        int bit = n >> 1;
        for(; j & bit; bit >>= 1) j ^= bit;
        j ^= bit;
        if(i < j) swap(a[i], a[j]);
    }

    for(int len = 2; len <= n; len <<= 1) {
        double ang = 2 * PI / len * (inv ? -1 : 1);
        cd wlen(cos(ang), sin(ang));

        for(int i = 0; i < n; i += len) {
            cd w = 1;
            for(int j = 0; j < len / 2; j++) {
                cd u = a[i + j], v = a[i + j + len / 2] * w;
                a[i + j] = u + v;
                a[i + j + len / 2] = u - v;
                w *= wlen;
            }
        }
    }

    if(inv) {
        for(cd& x : a) x /= n;
    }
}

vector<ll> mul(const vector<ll>& a, const vector<ll>& b) {
    int rs = a.size() + b.size() - 1;
    int sz = 1;
    while(sz < rs) sz <<= 1;

    vector<cd> fa(sz), fb(sz);
    for(int i = 0; i < (int)a.size(); i++) fa[i] = a[i];
    for(int i = 0; i < (int)b.size(); i++) fb[i] = b[i];

    fft(fa, false);
    fft(fb, false);

    for(int i = 0; i < sz; i++) fa[i] *= fb[i];

    fft(fa, true);

    vector<ll> res(rs);
    for(int i = 0; i < rs; i++) res[i] = llround(fa[i].real());
    return res;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    string s;
    cin >> s;

    int n = s.size();

    int S = count(s.begin(), s.end(), '1');
    vector<ll> cnt(S + 1, 0);

    int p = 0;
    cnt[0]++;

    for(char ch : s) {
        if(ch == '1') p++;
        cnt[p]++;
    }

    vector<ll> ans(n + 1, 0);

    for(ll x : cnt) ans[0] += x * (x - 1) / 2;

    if(S) {
        vector<ll> A = cnt;
        vector<ll> B(cnt.rbegin(), cnt.rend());

        vector<ll> r = mul(A, B);

        for(int k = 1; k <= S; k++) {
            ans[k] = r[S + k];
        }
    }

    // if(S >= 1){
    //     vector<ll> A=cnt, B(cnt.rbegin(), cnt.rend());
    //     vector<ll> r1=mul(A,B,M1), r2=mul(A,B,M2);
    //     ll inv1=pw(M1%M2, M2-2, M2);
    //     for(int k=1;k<=min((ll)n,(ll)S);k++){
    //         int idx = S + k;
    //         if(idx >= (int)r1.size()) break;
    //         ll x1=r1[idx], x2=r2[idx];
    //         ll t=((x2-x1)%M2+M2)%M2; t=(__int128)t*inv1%M2;
    //         ll val=(x1 + (__int128)t*M1)% (M1*M2);
    //         ans[k]=val;
    //     }
    // }

    string out;
    out.reserve((n + 1) * 12);

    for(int k = 0; k <= n; k++) {
        out += to_string(ans[k]);
        out += ' ';
    }

    cout << out << '\n';
    return 0;
}
```

## Worked Example

For `101`, prefix sums are `[0,1,1,2]`, so frequencies are `[1,2,1]`. For $k=1$, the correlation is $1\cdot2+2\cdot1=4$. For $k=0$, $\binom12+\binom22+\binom12=1$.

## Takeaway

If answers ask for every possible difference between prefix statistics, frequency cross-correlation and convolution can replace a separate scan for every difference.

### Related problems

One Bit Positions and signal-processing tasks use the same correlation-through-convolution transformation.

