#include <bits/stdc++.h>
using namespace std;
#pragma GCC optimize("O3,unroll-loops")
#define pb push_back
#define f first
#define s second
typedef long long ll;
typedef pair<ll, ll> ii;
typedef vector<ll> vi;
typedef vector<ii> vii;
typedef unsigned long long ull;
const ll MOD = 1e9 + 7;
const int INF = 1e9;

struct DSU{
    vector<int> p, sz, xr;
    DSU(int n){
        p.resize(n+1);
        sz.assign(n+1, 1);
        xr.assign(n+1, 0);
        iota(p.begin(), p.end(), 0);
    }
    pair<int,int> find(int x){
        if(p[x]==x) return {x, 0};
        auto q = find(p[x]);
        p[x] = q.f;
        xr[x] ^= q.s;
        return {p[x], xr[x]};
    }
    bool unite(int a, int b, int w){
        auto A = find(a), B = find(b);
        int ra = A.f, rb = B.f, xa = A.s, xb = B.s;
        if(ra==rb) return ((xa^xb)==w);
        if(sz[ra] < sz[rb]){
            swap(ra, rb);
            swap(xa, xb);
        }
        p[rb] = ra;
        xr[rb] = xa^xb^w;
        sz[ra] += sz[rb];
        return true;
    }
    int val(int x){
        return find(x).s;
    }
};

